# @cctt_verify {"v":2,"sym":"sympy.utilities.tests.test_wester.test_O4","kind":"function","src_hash":"b8eb16ddbe0a4bc9","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"test_O4()","rhs":"test_O4 produces the expected output","over":{"base":"Any"},"name":"test_O4_correct"},"guarantee":"test_O4 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.utilities.tests.test_wester.test_O4_correct","statement":"Path(test_O4(x), test_O4 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"05d49bf7bd5ad3f5"}
def test_O4():
    from sympy.vector import CoordSys3D, Del
    N = CoordSys3D("N")
    delop = Del()
    i, j, k = N.base_vectors()
    x, y, z = N.base_scalars()
    F = i*(x*y*z) + j*((x*y*z)**2) + k*((y**2)*(z**3))
    assert delop.cross(F).doit() == (-2*x**2*y**2*z + 2*y*z**3)*i + x*y*j + (2*x*y**2*z**2 - x*z)*k

