# ╚════════════════════════════════════════════════════════════╝
# @cctt_verify {"v":2,"sym":"sympy.utilities.tests.test_wester.test_Y7","kind":"function","src_hash":"a9e0257ca3aaace1","in":{"base":"Any"},"out":{"base":"Any","pred":"F == 2 * Sum((-1) ** n * exp(-a * n * s) / s, (n, 1, oo)) + 1 / s"},"spec":{"lhs":"test_Y7()","rhs":"test_Y7 produces the expected output","over":{"base":"Any"},"name":"test_Y7_correct"},"guarantee":"test_Y7 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.utilities.tests.test_wester.test_Y7_correct","statement":"Path(test_Y7(x), test_Y7 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"5e79d04384d7f8d8"}
def test_Y7():
    # What is the Laplace transform of an infinite square wave?
    # => 1/s + 2 sum( (-1)^n e^(- s n a)/s, n = 1..infinity )
    #    [Sanchez, Allen and Kyner, p. 213]
    t = symbols('t', positive=True)
    a = symbols('a', real=True)
    s = symbols('s')
    F, _, _ = laplace_transform(1 + 2*Sum((-1)**n*Heaviside(t - n*a),
                                          (n, 1, oo)), t, s)
    # returns 2*LaplaceTransform(Sum((-1)**n*Heaviside(-a*n + t),
    #                                (n, 1, oo)), t, s) + 1/s
    # https://github.com/sympy/sympy/issues/7177
    assert F == 2*Sum((-1)**n*exp(-a*n*s)/s, (n, 1, oo)) + 1/s


